function GallerySection() {
  const [selected, setSelected] = useState(null);
  const [filter, setFilter] = useState("Semua");
  const categories = ["Semua", "Diagnosa", "Fasilitas", "Overhaul", "Kelistrikan", "Showcase"];
  const filtered = filter === "Semua" ? GALLERY : GALLERY.filter(g => g.category === filter);

  return (
    <section id="galeri" style={{ background: "#080808", padding: "100px 24px", position: "relative" }}>
      <div style={{ position: "absolute", top: 0, left: 0, right: 0, height: 1, background: "linear-gradient(90deg, transparent, rgba(255,204,0,0.15), transparent)" }} />
      <div style={{ maxWidth: 1280, margin: "0 auto" }}>
        <FadeIn>
          <div style={{ textAlign: "center", marginBottom: 40 }}>
            <span style={{ color: "#FFCC00", fontSize: 12, fontWeight: 700, letterSpacing: 3, textTransform: "uppercase" }}>Galeri Bengkel</span>
            <h2 style={{ color: "#fff", fontSize: "clamp(28px, 4vw, 44px)", fontWeight: 900, margin: "12px 0 16px", letterSpacing: -1.5 }}>
              Lihat Langsung <span style={{ color: "#FFCC00" }}>Hasil Kerja</span> Kami
            </h2>
            <p style={{ color: "#666", fontSize: 15, maxWidth: 550, margin: "0 auto" }}>
              Dari diagnosa komputer hingga overhaul mesin — semuanya dikerjakan dengan alat profesional dan keahlian bertahun-tahun.
            </p>
          </div>
        </FadeIn>
        <FadeIn delay={0.1}>
          <div style={{ display: "flex", gap: 8, justifyContent: "center", flexWrap: "wrap", marginBottom: 32 }}>
            {categories.map(c => (
              <button key={c} onClick={() => setFilter(c)} style={{
                background: filter === c ? "rgba(255,204,0,0.15)" : "rgba(255,255,255,0.03)",
                color: filter === c ? "#FFCC00" : "#666",
                border: `1px solid ${filter === c ? "rgba(255,204,0,0.3)" : "rgba(255,255,255,0.06)"}`,
                padding: "8px 18px", borderRadius: 8, fontSize: 13, fontWeight: 600, cursor: "pointer",
                transition: "all 0.3s",
              }}>{c}</button>
            ))}
          </div>
        </FadeIn>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 12 }} className="gallery-grid">
          {filtered.map((img, i) => (
            <FadeIn key={i} delay={i * 0.06}>
              <div
                onClick={() => setSelected(selected === i ? null : i)}
                style={{
                  borderRadius: 12, overflow: "hidden", cursor: "pointer", position: "relative",
                  aspectRatio: "4/3", border: "1px solid rgba(255,255,255,0.06)",
                  transition: "all 0.4s",
                }}
                onMouseEnter={e => { e.currentTarget.style.borderColor = "rgba(255,204,0,0.3)"; e.currentTarget.style.transform = "scale(1.02)"; }}
                onMouseLeave={e => { e.currentTarget.style.borderColor = "rgba(255,255,255,0.06)"; e.currentTarget.style.transform = "none"; }}>
                <img src={img.src} alt={img.caption} style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }} />
                <div style={{
                  position: "absolute", inset: 0,
                  background: "linear-gradient(0deg, rgba(0,0,0,0.8) 0%, transparent 50%)",
                  display: "flex", alignItems: "flex-end", padding: 14,
                }}>
                  <div>
                    <span style={{ background: "rgba(255,204,0,0.2)", color: "#FFCC00", fontSize: 10, fontWeight: 700, padding: "3px 8px", borderRadius: 4, letterSpacing: 0.5 }}>{img.category}</span>
                    <div style={{ color: "#ddd", fontSize: 12, marginTop: 6, lineHeight: 1.4 }}>{img.caption}</div>
                  </div>
                </div>
              </div>
            </FadeIn>
          ))}
        </div>
        <FadeIn delay={0.4}>
          <div style={{ textAlign: "center", marginTop: 32 }}>
            <a href="https://www.instagram.com/mb_renaultspecialist/" target="_blank" rel="noopener" style={{
              display: "inline-flex", alignItems: "center", gap: 8, color: "#FFCC00", fontSize: 14,
              fontWeight: 600, textDecoration: "none", padding: "12px 24px", borderRadius: 10,
              border: "1px solid rgba(255,204,0,0.2)", transition: "all 0.3s",
            }}
            onMouseEnter={e => e.currentTarget.style.background = "rgba(255,204,0,0.08)"}
            onMouseLeave={e => e.currentTarget.style.background = "transparent"}>
              <Instagram size={16} /> Lihat Lebih Banyak di Instagram
            </a>
          </div>
        </FadeIn>
      </div>
    </section>
  );
}

