function FloatingWA() {
  const [pulse, setPulse] = useState(true);
  return (
    <a href={WA_LINK} target="_blank" rel="noopener" style={{
      position: "fixed", bottom: 24, right: 24, zIndex: 999, width: 60, height: 60,
      background: "linear-gradient(135deg, #25D366, #128C7E)", borderRadius: "50%",
      display: "flex", alignItems: "center", justifyContent: "center",
      boxShadow: "0 4px 20px rgba(37,211,102,0.4)", transition: "transform 0.3s",
      animation: pulse ? "waPulse 2s infinite" : "none",
    }}
    onMouseEnter={e => { e.currentTarget.style.transform = "scale(1.1)"; setPulse(false); }}
    onMouseLeave={e => { e.currentTarget.style.transform = "scale(1)"; setPulse(true); }}>
      <MessageCircle size={26} color="#fff" fill="#fff" />
    </a>
  );
}

